/**
 * Pick N examples filtered by category and outcome
 */
export function pickExamples(category, count = 3, outcome = "success") {
  let pool = GOLDEN_EXAMPLES.filter((e) => e.outcome === outcome);
  if (category) {
    const filtered = pool.filter((e) => e.category === category);
    if (filtered.length >= count) pool = filtered;
  }
  // Shuffle
  const shuffled = [...pool].sort(() => Math.random() - 0.5);
  return shuffled.slice(0, count);
}

/**
 * Format examples as a text block for injection into a system prompt
 */
export function formatExamplesForPrompt(examples) {
  if (!examples || examples.length === 0) return "";
  return examples
    .map((ex, i) => {
      const convo = ex.conversation
        .map((m) => `[${m.role}]: ${m.content}`)
        .join("\n");
      return `--- ESEMPIO ${i + 1} (${ex.outcome.toUpperCase()} — ${ex.category}) ---\nOperatore: ${ex.operatorId}\nCommento: ${ex.commentary}\n\n${convo}`;
    })
    .join("\n\n");
}
